<template>
  <button
    class="io-btn"
    :class="buttonClass"
    type="button"
    @click="$emit('click')"
  >
    {{ label }}
  </button>
</template>

<script>
export default {
  name: 'IoButton',
  emits: ['click'],
  props: {
    label: {
      type: String,
      default: 'Button'
    },
    buttonType: {
      type: String,
      default: 'primary'
    }
  },
  computed: {
    buttonClass() {
      return `io-btn--${this.buttonType}`
    }
  }
}
</script>

<style scoped>
.io-btn {
  border: 1px solid rgba(255, 255, 255, 0.7);
  border-radius: 999px;
  background: transparent;
  color: #fff;
  cursor: pointer;
  font-size: 1rem;
  letter-spacing: 0.08em;
  padding: 0.75rem 1.25rem;
  text-transform: uppercase;
  transition: all 0.2s ease;
}

.io-btn:hover {
  border-color: #fff;
  opacity: 1;
  transform: translateY(-1px);
}

.io-btn--no-border {
  border-color: transparent;
}
</style>
